sql:
SELECT drug_id, disease_id
FROM drug_disease_predictions
WHERE predict_score < 0.5;

SELECT drug_id
FROM clinical_trials
WHERE lead_institution = 'Harvard Medical School';

SELECT drug_id, disease_id
FROM drug_disease_indications
WHERE approval_status = 'Approved' AND indication_source = 'Clinical trial';

external_knowledge:
- 'Beacons of hope' metaphorically represent the drugs that are potential treatments; 
- 'Given the green light' refers to the approval status of the indication for a disease being 'Approved';
- 'Dragon' is a metaphor for the specific disease that the drugs are intended to treat;
- 'Chances of victory' metaphorically represent the predicted score indicating the likelihood of the drug being effective for the disease.

sql:
SELECT drug_id, drug_name
FROM drugs
WHERE molecular_weight < 300;

SELECT drug_name 
FROM drugs 
WHERE molecular_weight = (SELECT MAX(molecular_weight) FROM drugs);
